import axios from 'axios';

const api = axios.create({
  baseURL: process.env.REACT_APP_API_URL, // e.g. http://localhost:8080/api
  headers: {
    'Content-Type': 'application/json',
  },
});

// ✅ JWT Interceptor
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('nfxtoken') || sessionStorage.getItem('nfxtoken');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => Promise.reject(error)
);

api.interceptors.response.use(
  (response) => response.data,
  (error) => {
    console.error('API error:', error.response?.data?.message || error.message);
    return Promise.reject(error);
  }
);

export default {
  async login(email, password, rememberMe) {
    // ✅ Match backend -> /api/auth/login
    const response = await api.post('/auth/login', { email, password });
    const { token } = response;
    if (token) {
      if (rememberMe) {
        localStorage.setItem('nfxtoken', token);
      } else {
        sessionStorage.setItem('nfxtoken', token);
      }
    }
    return response;
  },

  async signup(email, password) {
    // ✅ Match backend -> /api/auth/signup
    return api.post('/auth/signup', { email, password });
  },

  async forgotPassword(email) {
    return api.post('/auth/forgot-password', { email });
  },

  async getVehicles() {
    return api.get('/vehicles');
  },

  async getAlerts() {
    return api.get('/alerts');
  },

  logout() {
    localStorage.removeItem('nfxtoken');
    sessionStorage.removeItem('nfxtoken');
  },
};
